theory.syntax:
SELECT outer_columns FROM (
  SELECT columns FROM table_name GROUP BY column_name
) AS derived_alias
WHERE condition;

example.query:
-- 1. Filtering on top of a pre-aggregated derived table
SELECT * FROM (
  SELECT city, AVG(marks) AS avg_marks FROM Students GROUP BY city
) AS city_avg
WHERE avg_marks > 70;

-- 2. Joining a derived table back to the original table
SELECT s.name, s.marks, city_avg.avg_marks FROM Students AS s
JOIN (SELECT city, AVG(marks) AS avg_marks FROM Students GROUP BY city) AS city_avg
ON s.city = city_avg.city;
